import React from 'react';
import { Slot } from '@radix-ui/react-slot';
import { getButtonStyleKeys, isButtonDisabled } from '../lib/core';
import type { ButtonBaseProps } from '../lib/core';
import styles from './button.module.scss';

export interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement>, ButtonBaseProps {}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
	({ className = '', variant = 'default', size = 'default', asChild = false, loading = false, disabled, children, ...props }, ref) => {
		const Comp = asChild ? Slot : 'button';
		const styleKeys = getButtonStyleKeys(variant, size);

		const classes = [styles[styleKeys.base], styles[styleKeys.variant], styles[styleKeys.size], className].filter(Boolean).join(' ');

		return (
			<Comp ref={ref} className={classes} disabled={isButtonDisabled(disabled, loading)} {...props}>
				{loading && (
					<svg
						className={styles.spinner}
						xmlns="http://www.w3.org/2000/svg"
						width="16"
						height="16"
						viewBox="0 0 24 24"
						fill="none"
						stroke="currentColor"
						strokeWidth="2"
						strokeLinecap="round"
						strokeLinejoin="round">
						<circle cx="12" cy="12" r="10" />
					</svg>
				)}
				{children}
			</Comp>
		);
	},
);

Button.displayName = 'Button';

export { Button };
export default Button;

@use 'sass:color';
@use 'variables/colors' as *;

.button {
	display: inline-flex;
	align-items: center;
	justify-content: center;
	gap: $spacing-2;
	white-space: nowrap;
	border-radius: $radius;
	font-size: $text-sm;
	font-weight: $font-medium;
	transition: all $transition-fast;
	cursor: pointer;
	outline: none;

	&:focus-visible {
		outline: none;
		box-shadow:
			0 0 0 2px $background,
			0 0 0 4px $ring;
	}

	&:disabled,
	&.disabled {
		pointer-events: none;
		opacity: 0.5;
		cursor: not-allowed;
	}

	svg {
		pointer-events: none;
		width: 1em;
		height: 1em;
	}

	// 尺寸变体
	&.sizeDefault {
		height: 2.25rem;
		padding: 0 $spacing-4;

		&.hasIcon {
			padding-inline: $spacing-3;
		}
	}

	&.sizeSm {
		height: 2rem;
		border-radius: $radius-sm;
		padding: 0 $spacing-3;
		font-size: $text-xs;

		&.hasIcon {
			padding-inline: $spacing-2;
			gap: $spacing-1;
		}
	}

	&.sizeLg {
		height: 2.5rem;
		border-radius: $radius-md;
		padding: 0 $spacing-6;
		font-size: $text-base;

		&.hasIcon {
			padding-inline: $spacing-4;
		}
	}

	&.sizeIcon {
		height: 2.25rem;
		width: 2.25rem;
		padding: 0;
	}

	// 样式变体
	&.variantDefault {
		background-color: $primary;
		color: $primary-foreground;
		border: none;
		box-shadow: $shadow-sm;

		&:hover:not(:disabled) {
			background-color: color.mix(black, $primary, 10%);
		}

		&:active:not(:disabled) {
			background-color: color.mix(black, $primary, 20%);
		}
	}

	&.variantDestructive {
		background-color: $destructive;
		color: $destructive-foreground;
		border: none;
		box-shadow: $shadow-sm;

		&:hover:not(:disabled) {
			background-color: color.mix(black, $destructive, 10%);
		}
	}

	&.variantOutline {
		background-color: transparent;
		color: $foreground;
		border: 1px solid $border;
		box-shadow: $shadow-sm;

		&:hover:not(:disabled) {
			background-color: $accent;
			color: $accent-foreground;
		}
	}

	&.variantSecondary {
		background-color: $secondary;
		color: $secondary-foreground;
		border: none;
		box-shadow: $shadow-sm;

		&:hover:not(:disabled) {
			background-color: color.mix(black, $secondary, 10%);
		}
	}

	&.variantGhost {
		background-color: transparent;
		color: $foreground;

		&:hover:not(:disabled) {
			background-color: $accent;
			color: $accent-foreground;
		}
	}

	&.variantLink {
		background-color: transparent;
		color: $primary;
		text-decoration: underline;
		text-underline-offset: 4px;

		&:hover:not(:disabled) {
			text-decoration: none;
		}
	}
}
